import{_ as t,C as l,o as i,c as r,a2 as a,E as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"架构拆分笔记：控制面和执行面分开","description":"","frontmatter":{},"headers":[],"relativePath":"agent/architecture-split-notes.md","filePath":"agent/architecture-split-notes.md","lastUpdated":1782915681000}'),B={name:"agent/architecture-split-notes.md"};function A(n,E,p,s,c,d){const e=l("Mermaid");return i(),r("div",null,[E[0]||(E[0]=a('<h1 id="架构拆分笔记-控制面和执行面分开" tabindex="-1">架构拆分笔记：控制面和执行面分开 <a class="header-anchor" href="#架构拆分笔记-控制面和执行面分开" aria-label="Permalink to &quot;架构拆分笔记：控制面和执行面分开&quot;">​</a></h1><p>Agent 项目从 demo 往长期维护走，真正的转折点不是接更多模型，而是把控制面和执行面分开。</p><p>模型执行是不确定的，业务控制必须确定。这两者混在一起，后面很多问题都会变得难排查。</p><h2 id="单体阶段为什么会变重" tabindex="-1">单体阶段为什么会变重 <a class="header-anchor" href="#单体阶段为什么会变重" aria-label="Permalink to &quot;单体阶段为什么会变重&quot;">​</a></h2><p>早期一个服务做所有事：接用户请求，写消息，调模型，执行工具，推流返回。</p><p>这个阶段开发很快。但功能增加后，问题会集中出现：</p><ul><li>模型慢会拖住业务 API。</li><li>工具失败会影响主请求。</li><li>沙箱任务耗时长，取消和超时不好处理。</li><li>后台任务和用户请求抢资源。</li><li>前端刷新后依赖执行内存。</li><li>审计、用量、记忆、知识索引都混在主链路里。</li></ul><p>单体不是不能做，而是要知道它的边界。</p><h2 id="更稳的拆分方式" tabindex="-1">更稳的拆分方式 <a class="header-anchor" href="#更稳的拆分方式" aria-label="Permalink to &quot;更稳的拆分方式&quot;">​</a></h2>',9)),o(e,{code:"flowchart%20TB%0A%20%20%20%20Client%5B%22%E5%89%8D%E7%AB%AF%20%2F%20%E5%AE%A2%E6%88%B7%E7%AB%AF%22%5D%20--%3E%20Control%5B%22%E6%8E%A7%E5%88%B6%E9%9D%A2%3Cbr%2F%3E%E8%AE%A4%E8%AF%81%E3%80%81%E4%BC%9A%E8%AF%9D%E3%80%81%E4%BB%BB%E5%8A%A1%E3%80%81%E4%BA%8B%E4%BB%B6%22%5D%0A%20%20%20%20Control%20--%3E%20Runtime%5B%22%E6%89%A7%E8%A1%8C%E9%9D%A2%3Cbr%2F%3E%E4%B8%8A%E4%B8%8B%E6%96%87%E3%80%81%E6%A8%A1%E5%9E%8B%E3%80%81%E5%B7%A5%E5%85%B7%E3%80%81%E6%B2%99%E7%AE%B1%22%5D%0A%20%20%20%20Runtime%20--%3E%20EventBus%5B%22%E4%BA%8B%E4%BB%B6%E6%80%BB%E7%BA%BF%22%5D%0A%20%20%20%20EventBus%20--%3E%20Live%5B%22%E5%AE%9E%E6%97%B6%E6%B5%81%3Cbr%2F%3E%E7%94%A8%E6%88%B7%E4%BD%93%E9%AA%8C%22%5D%0A%20%20%20%20EventBus%20--%3E%20Durable%5B%22%E6%8C%81%E4%B9%85%E4%BA%8B%E4%BB%B6%3Cbr%2F%3E%E6%81%A2%E5%A4%8D%E3%80%81%E5%AE%A1%E8%AE%A1%22%5D%0A%20%20%20%20Runtime%20--%3E%20Callback%5B%22%E5%AE%8C%E6%88%90%E5%9B%9E%E8%B0%83%22%5D%0A%20%20%20%20Callback%20--%3E%20Workers%5B%22%E5%90%8E%E5%8F%B0%E6%B2%BB%E7%90%86%3Cbr%2F%3E%E8%AE%B0%E5%BF%86%E3%80%81%E7%9F%A5%E8%AF%86%E3%80%81%E5%AE%A1%E8%AE%A1%E3%80%81%E7%94%A8%E9%87%8F%22%5D%0A%20%20%20%20Durable%20--%3E%20Projection%5B%22%E5%8E%86%E5%8F%B2%E6%8A%95%E5%BD%B1%20%2F%20%E7%8A%B6%E6%80%81%E5%BF%AB%E7%85%A7%22%5D%0A%20%20%20%20Projection%20--%3E%20Client%0A"}),E[1]||(E[1]=a('<p>控制面拥有业务事实：用户、会话、任务状态、事件、权限。执行面负责不确定执行：模型、工具、沙箱、上下文。</p><p>实时流服务体验，持久事件服务恢复。后台治理处理那些不该阻塞用户请求，但又必须完成的事情。</p><h2 id="这个拆法的代价" tabindex="-1">这个拆法的代价 <a class="header-anchor" href="#这个拆法的代价" aria-label="Permalink to &quot;这个拆法的代价&quot;">​</a></h2><p>链路变长是事实。一次请求可能跨控制面、执行面、事件总线、回调、后台任务。排查问题需要更多日志和 trace。</p><p>但它换来的是隔离：</p><ul><li>执行面压力大时可以独立扩容。</li><li>后台任务失败不会阻塞用户请求。</li><li>前端恢复依赖持久事件，不依赖执行进程内存。</li><li>模型和工具失败不会直接污染业务入口。</li></ul><h2 id="踩过的坑" tabindex="-1">踩过的坑 <a class="header-anchor" href="#踩过的坑" aria-label="Permalink to &quot;踩过的坑&quot;">​</a></h2><p>第一个坑，是业务服务直接跑模型。短期省事，长期会被延迟、取消、失败拖住。</p><p>第二个坑，是把实时流当历史。实时通道适合看过程，不适合做事实源。</p><p>第三个坑，是共享层膨胀。共享层只应该放稳定契约，不要变成所有临时代码的堆放地。</p><p>第四个坑，是内部接口缺少治理。服务拆开后，内部调用也需要认证、幂等、重试和审计。</p><p>第五个坑，是后台任务没有可观测性。记忆、知识、审计看似边缘，但会影响长期体验。</p><h2 id="现在的记录" tabindex="-1">现在的记录 <a class="header-anchor" href="#现在的记录" aria-label="Permalink to &quot;现在的记录&quot;">​</a></h2><p>如果再做一次，我会更早补端到端事件测试。一次任务从提交、执行、工具、完成到后台任务，都应该能验证。</p><p>可观测性也要早做：模型延迟、工具失败、事件积压、后台任务延迟、沙箱健康，都要能看到。</p><p>一句话总结：架构拆分的目的不是显得复杂，而是把模型和工具的不确定性挡在业务控制面之外。</p><h2 id="podcast-提纲" tabindex="-1">Podcast 提纲 <a class="header-anchor" href="#podcast-提纲" aria-label="Permalink to &quot;Podcast 提纲&quot;">​</a></h2><ol><li>为什么单体 Agent demo 后期会变重。</li><li>控制面和执行面分别负责什么。</li><li>实时流和持久事件为什么要分开。</li><li>后台任务为什么也是治理面。</li><li>共享层如何避免失控。</li><li>内部接口为什么也要安全和幂等。</li><li>如果重做，我会先补哪些观测和测试。</li></ol>',18))])}const _=t(B,[["render",A]]);export{u as __pageData,_ as default};
